#include <stdio.h>
#include <math.h>
#define MOD 2003
long long powmod(long long a, long long b, long long mod) {
    long long res = 1;
    while (b > 0) {
        if (b & 1) res = (res * a) % mod;
        a = (a * a) % mod;
        b >>= 1;
    }
    return res;
}
long long inv(long long a, long long mod) {
    return powmod(a, mod - 2, mod);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long N, K, L, F;
        scanf("%lld %lld %lld %lld", &N, &K, &L, &F);
        long long ans = 0;
        for (int i = 0; i <= N; i++) {
            long long prob = 1;
            for (int j = 1; j <= L; j++) {
                prob = (prob * (N - i + F - 1)) / (N - i + j * F - 1);
            }
            prob = (prob * powmod(K - 1, N - i, MOD)) % MOD;
            prob = (prob * powmod(K, i, MOD)) % MOD;
            prob = (prob * inv(powmod(K, N, MOD), MOD)) % MOD;
            ans = (ans + prob) % MOD;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

