import java.util.Scanner;
public class Main {
    static final long MOD = 2003;
    public static long powmod(long a, long b, long mod) {
        long res = 1;
        while (b > 0) {
            if (b % 2 == 1) res = (res * a) % mod;
            a = (a * a) % mod;
            b >>= 1;
        }
        return res;
    }
    public static long inv(long a, long mod) {
        return powmod(a, mod - 2, mod);
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long N = sc.nextLong();
            long K = sc.nextLong();
            long L = sc.nextLong();
            long F = sc.nextLong();
            long ans = 0;
            for (int i = 0; i <= N; i++) {
                long prob = 1;
                for (int j = 1; j <= L; j++) {
                    prob = (prob * (N - i + F - 1)) / (N - i + j * F - 1);
                }
                prob = (prob * powmod(K - 1, N - i, MOD)) % MOD;
                prob = (prob * powmod(K, i, MOD)) % MOD;
                prob = (prob * inv(powmod(K, N, MOD), MOD)) % MOD;
                ans = (ans + prob) % MOD;
            }
            System.out.println(ans);
        }
    }
}

